import { Component } from '@angular/core';
import { Router } from '@angular/router';
import { Observable } from 'rxjs';
import { User } from './core/models/user.model';
import { AuthService } from './core/services/auth.service';

@Component({
  selector: 'app-root',
  templateUrl: './app.component.html'
})
export class AppComponent {
  readonly user$: Observable<User | null>;

  constructor(private readonly auth: AuthService, private readonly router: Router) {
    this.user$ = this.auth.currentUser$;
  }

  logout(): void {
    this.auth.logout();
    this.router.navigateByUrl('/login');
  }
}
<header class="shell-header">
  <a class="brand" routerLink="/workspace" aria-label="Mini CRM Access Console">
    <span class="brand-mark">MC</span>
    <span>
      <strong>Mini CRM</strong>
      <small>Access Console</small>
    </span>
  </a>

  <nav *ngIf="user$ | async as user">
    <a routerLink="/workspace" routerLinkActive="active">Workspace</a>
    <a *ngIf="user.role === 'Admin'" routerLink="/admin/users" routerLinkActive="active">Users</a>
    <button type="button" (click)="logout()">Sign out</button>
  </nav>
</header>

<main>
  <router-outlet></router-outlet>
</main>
